+
+<EditForm EditContext="editContext" OnValidSubmit="HandleSubmit" FormName="book-appointment">
+    <DataAnnotationsValidator />
+    <CustomValidator @ref="customValidator" />
+
+    <h3>Step 1: Patient Information</h3>
+
+    <div class="mb-3">
+        <label class="form-label">Patient Name</label>
+        <InputText class="form-control" @bind-Value="model.PatientName" />
+        <ValidationMessage For="() => model.PatientName" />
+    </div>
+
+    <div class="mb-3">
+        <label class="form-label">Email</label>
+        <InputText class="form-control" @bind-Value="model.Email" />
+        <ValidationMessage For="() => model.Email" />
+    </div>
+
+    <div class="mb-3">
+        <label class="form-label">Phone</label>
+        <InputText class="form-control" @bind-Value="model.Phone" />
+        <ValidationMessage For="() => model.Phone" />
+    </div>
+
+    <div class="mb-3">
+        <label class="form-label">Insurance Provider</label>
+        <InputSelect class="form-select" @bind-Value="model.InsuranceProvider">
+            <option value="">-- Select --</option>
+            <option value="Aetna">Aetna</option>
+            <option value="BlueCross">BlueCross</option>
+            <option value="Cigna">Cigna</option>
+            <option value="UnitedHealth">UnitedHealth</option>
+            <option value="None">None</option>
+        </InputSelect>
+        <ValidationMessage For="() => model.InsuranceProvider" />
+    </div>
+
+    @if (!showStep2)
+    {
+        <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
+    }
+
+    @if (showStep2)
+    {
+        <h3 class="mt-4">Step 2: Appointment Details</h3>
+
+        <div class="mb-3">
+            <label class="form-label">Preferred Doctor</label>
+            <InputSelect class="form-select" @bind-Value="model.Doctor" @bind:after="OnDoctorOrDateChanged">
+                <option value="">-- Select --</option>
+                @foreach (var doc in doctors)
+                {
+                    <option value="@doc">@doc</option>
+                }
+            </InputSelect>
+            <ValidationMessage For="() => model.Doctor" />
+        </div>
+
+        <div class="mb-3">
+            <label class="form-label">Date</label>
+            <InputDate class="form-control" @bind-Value="model.AppointmentDate" @bind:after="OnDoctorOrDateChanged" />
+            <ValidationMessage For="() => model.AppointmentDate" />
+        </div>
+
+        <div class="mb-3">
+            <label class="form-label">Time Slot</label>
+            <InputSelect class="form-select" @bind-Value="model.TimeSlot">
+                <option value="">-- Select --</option>
+                @foreach (var slot in availableSlots)
+                {
+                    <option value="@slot">@slot</option>
+                }
+            </InputSelect>
+            <ValidationMessage For="() => model.TimeSlot" />
+        </div>
+
+        <div class="mb-3">
+            <label class="form-label">Reason for Visit</label>
+            <InputTextArea class="form-control" @bind-Value="model.Reason" rows="3" />
+            <ValidationMessage For="() => model.Reason" />
+        </div>
+
+        <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
+            @(isSubmitting ? "Checking..." : "Check Availability")
+        </button>
+        <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || isSubmitting)">
+            Confirm Appointment
+        </button>
+    }
+</EditForm>
+
+@if (appointmentConfirmed)
+{
+    <div class="alert alert-success mt-3">Appointment booked successfully!</div>
+}
+
+@code {
+    private EditContext editContext = default!;
+    private AppointmentFormModel model = new();
+    private CustomValidator? customValidator;
+
+    private bool showStep2;
+    private bool isSubmitting;
+    private bool availabilityChecked;
+    private bool appointmentConfirmed;
+
+    private List<string> doctors = new();
+    private List<string> availableSlots = new();
+
+    protected override async Task OnInitializedAsync()
+    {
+        editContext = new EditContext(model);
+        doctors = await AppointmentService.GetDoctorsAsync();
+    }
+
+    private void ProceedToStep2()
+    {
+        customValidator?.ClearErrors();
+
+        var isValid = editContext.Validate();
+        if (!isValid) return;
+
+        // Check step 1 fields specifically
+        var step1Valid =
+            !string.IsNullOrWhiteSpace(model.PatientName) &&
+            !string.IsNullOrWhiteSpace(model.Email) &&
+            !string.IsNullOrWhiteSpace(model.Phone) &&
+            !string.IsNullOrWhiteSpace(model.InsuranceProvider);
+
+        if (step1Valid)
+        {
+            showStep2 = true;
+        }
+    }
+
+    private async Task OnDoctorOrDateChanged()
+    {
+        availabilityChecked = false;
+        if (!string.IsNullOrEmpty(model.Doctor) && model.AppointmentDate.HasValue)
+        {
+            availableSlots = await AppointmentService.GetAvailableSlotsAsync(
+                model.Doctor, model.AppointmentDate.Value);
+        }
+    }
+
+    private async Task CheckAvailability()
+    {
+        customValidator?.ClearErrors();
+        availabilityChecked = false;
+        isSubmitting = true;
+
+        try
+        {
+            // Validate step 2 fields locally first
+            if (string.IsNullOrWhiteSpace(model.Doctor) ||
+                !model.AppointmentDate.HasValue ||
+                string.IsNullOrWhiteSpace(model.TimeSlot) ||
+                string.IsNullOrWhiteSpace(model.Reason))
+            {
+                editContext.Validate();
+                return;
+            }
+
+            if (model.AppointmentDate.Value <= DateOnly.FromDateTime(DateTime.Today))
+            {
+                customValidator?.DisplayErrors(new Dictionary<string, List<string>>
+                {
+                    [nameof(model.AppointmentDate)] = ["Appointment date must be in the future"]
+                });
+                return;
+            }
+
+            var errors = await AppointmentService.ValidatePatientAsync(
+                model.Email!, model.InsuranceProvider, model.Doctor!, model.TimeSlot!);
+
+            if (errors.Count > 0)
+            {
+                customValidator?.DisplayErrors(errors);
+            }
+            else
+            {
+                availabilityChecked = true;
+            }
+        }
+        finally
+        {
+            isSubmitting = false;
+        }
+    }
+
+    private async Task HandleSubmit()
+    {
+        if (!availabilityChecked) return;
+        appointmentConfirmed = true;
+        await Task.CompletedTask;
+    }
+
+    public class AppointmentFormModel
+    {
+        [Required(ErrorMessage = "Patient name is required")]
+        public string? PatientName { get; set; }
+
+        [Required(ErrorMessage = "Email is required")]
+        [EmailAddress(ErrorMessage = "Invalid email format")]
+        public string? Email { get; set; }
+
+        [Required(ErrorMessage = "Phone is required")]
+        public string? Phone { get; set; }
+
+        [Required(ErrorMessage = "Insurance provider is required")]
+        public string? InsuranceProvider { get; set; }
+
+        [Required(ErrorMessage = "Doctor is required")]
+        public string? Doctor { get; set; }
+
+        [Required(ErrorMessage = "Date is required")]
+        public DateOnly? AppointmentDate { get; set; }
+
+        [Required(ErrorMessage = "Time slot is required")]
+        public string? TimeSlot { get; set; }
+
+        [Required(ErrorMessage = "Reason is required")]
+        [MaxLength(500, ErrorMessage = "Reason must be 500 characters or fewer")]
+        public string? Reason { get; set; }
+    }
+}
+

